  ('social-worker-moex-07149', 'social-worker', 'social-worker-moex-101-7c9828ae', 'sub-social-worker-02', NULL, 'single_choice', '你是一個早療機構社工，有一位特教老師告訴你，根據她的觀察與評估，她高度懷疑其班上一位三歲幼 童受虐，並請你去通報，此時你該先做什麼？', '["向她說明與討論兒童虐待與疏忽的症狀，以確定其評估的正確性", "說明她應該自己通報，你會評估小孩狀況，並在通報過程協助她", "建議尋找與提供家庭諮商服務來協助該幼童家庭", "根據她口頭提供的評估資料趕快去通報兒童虐待"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "c13f7a6883c3", "answer_pdf_sha1": "e7b1dc7ed7a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0701", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
